import sys
from math import gcd
from functools import reduce

input = sys.stdin.read
data = input().split()

index = 0
t = int(data[index])
index += 1

for _ in range(t):
    n = int(data[index])
    index += 1
    a = [int(data[index + i]) for i in range(n)]
    index += n

    cnt = [0] * 30
    for val in a:
        for b in range(30):
            if val & (1 << b):
                cnt[b] += 1

    g = reduce(gcd, cnt, 0)

    ans = []
    if g == 0:
        ans = list(range(1, n + 1))
    else:
        for d in range(1, int(g ** 0.5) + 1):
            if g % d == 0:
                ans.append(d)
                if d != g // d:
                    ans.append(g // d)
        ans.sort()

    print(' '.join(map(str, ans)))

